import json

def solve(grid):
    # Find the non-zero number C
    C = 0
    last_row_with_C = -1
    for r, row in enumerate(grid):
        for cell in row:
            if cell != 0:
                C = cell
                last_row_with_C = r
                break
        if C != 0:
            break
            
    # If the grid is all zeros, return it as is
    if C == 0:
        return grid

    new_grid = [row[:] for row in grid]
    rows, cols = len(grid), len(grid[0])

    # Rule based on parity of C
    if C % 2 == 0:  # Even number rule (fill-left)
        for r in range(rows):
            rightmost_c_col = -1
            for c in range(cols - 1, -1, -1):
                if new_grid[r][c] == C:
                    rightmost_c_col = c
                    break
            
            if rightmost_c_col != -1:
                for c in range(rightmost_c_col + 1):
                    new_grid[r][c] = C
    else:  # Odd number rule (fill-right-and-down)
        # Horizontal fill
        for r in range(rows):
            leftmost_c_col = -1
            for c in range(cols):
                if new_grid[r][c] == C:
                    leftmost_c_col = c
                    break
            
            if leftmost_c_col != -1:
                for c in range(leftmost_c_col, cols):
                    new_grid[r][c] = C
        
        # Vertical fill (downwards)
        # We need the last row with C from the *original* grid.
        # Let's find that again.
        original_last_row_with_C = -1
        for r in range(rows):
            if C in grid[r]:
                 original_last_row_with_C = r

        if original_last_row_with_C != -1:
            for r in range(original_last_row_with_C + 1, rows):
                # The condition from analysis was "if the row was originally all zeros"
                # But in Example 2, the rows below are just filled regardless.
                # Let's stick to the simpler rule: fill all rows below the last original C row.
                new_grid[r] = [C] * cols

    return new_grid

def format_grid(grid):
    return "\n".join(" ".join(map(str, row)) for row in grid)

