import numpy as np

def solve_grid_puzzle(grid_str):
    """
    Solves the grid puzzle based on the observed rule.
    Rule: A line of '5's acts as a barrier. Other non-zero numbers ('fillers')
    propagate in a direction perpendicular to the barrier line, filling '0's
    until they hit the barrier or the grid edge.
    """
    # Parse the input string into a NumPy array
    grid = np.array([list(map(int, row.split())) for row in grid_str.strip().split('\n')])
    output_grid = grid.copy()
    rows, cols = grid.shape

    # Find barrier and fill direction
    barrier_val = 5
    is_vertical_barrier = False
    is_horizontal_barrier = False
    barrier_pos = -1

    # Check for vertical barrier
    for c in range(cols):
        if np.all(grid[:, c] == barrier_val):
            is_vertical_barrier = True
            barrier_pos = c
            break

    # If no vertical barrier, check for horizontal
    if not is_vertical_barrier:
        for r in range(rows):
            if np.all(grid[r, :] == barrier_val):
                is_horizontal_barrier = True
                barrier_pos = r
                break

    # Apply the fill logic
    if is_vertical_barrier:
        # Horizontal fill
        for r in range(rows):
            # Find fillers in the current row
            fillers = [(c, grid[r, c]) for c in range(cols) if grid[r, c] != 0 and grid[r, c] != barrier_val]
            for c_fill, val_fill in fillers:
                if c_fill < barrier_pos:
                    # Fill rightward from filler to barrier
                    for c in range(c_fill + 1, barrier_pos):
                        if output_grid[r, c] == 0:
                            output_grid[r, c] = val_fill
                else: # c_fill > barrier_pos
                    # Fill leftward from filler to barrier
                    for c in range(barrier_pos + 1, c_fill):
                         if output_grid[r, c] == 0:
                            output_grid[r, c] = val_fill

    elif is_horizontal_barrier:
        # Vertical fill
        for c in range(cols):
            # Find fillers in the current column
            fillers = [(r, grid[r, c]) for r in range(rows) if grid[r, c] != 0 and grid[r, c] != barrier_val]
            for r_fill, val_fill in fillers:
                if r_fill < barrier_pos:
                    # Fill downward from filler to barrier
                    for r in range(r_fill + 1, barrier_pos):
                        if output_grid[r, c] == 0:
                            output_grid[r, c] = val_fill
                else: # r_fill > barrier_pos
                    # Fill upward from filler to barrier
                    for r in range(barrier_pos + 1, r_fill):
                        if output_grid[r, c] == 0:
                            output_grid[r, c] = val_fill

    # Convert the final grid back to the required string format
    return "\n".join([" ".join(map(str, row)) for row in output_grid])

