                        output_grid[r,c] = left_fill_val
            if right_fill_val != 0:
                for c in range(barrier_pos + 1, cols):
                    if output_grid[r,c] == 0:
                        output_grid[r,c] = right_fill_val

    else: # Horizontal Barrier
        # Find horizontal barrier position
        for r_idx in range(rows):
            if np.all(grid[r_idx, :] == barrier_val):
                barrier_pos = r_idx
                break

        # Process columns for vertical fill
        for c in range(cols):
            top_fill_val = 0
            bottom_fill_val = 0
            # Find fillers
            for r in range(barrier_pos):
                if grid[r,c] != 0 and grid[r,c] != barrier_val:
                    top_fill_val = grid[r,c]
            for r in range(barrier_pos + 1, rows):
                 if grid[r,c] != 0 and grid[r,c] != barrier_val:
                    bottom_fill_val = grid[r,c]

            # Apply fills
            if top_fill_val != 0:
                for r in range(barrier_pos):
                    if output_grid[r,c] == 0:
                        output_grid[r,c] = top_fill_val
            if bottom_fill_val != 0:
                for r in range(barrier_pos + 1, rows):
                     if output_grid[r,c] == 0:
                        output_grid[r,c] = bottom_fill_val

    return "\n".join([" ".join(map(str, row)) for row in output_grid])

final_grid = solve_grid_puzzle_corrected(test_input)
print(final_grid)
