import json

def solve(grid):
    rows = len(grid)
    cols = len(grid[0])

    # Count horizontal and vertical adjacencies of non-zero numbers
    h_adj = 0
    v_adj = 0

    for r in range(rows):
        for c in range(cols):
            if grid[r][c] != 0:
                # Check horizontal neighbor
                if c + 1 < cols and grid[r][c+1] != 0:
                    h_adj += 1
                # Check vertical neighbor
                if r + 1 < rows and grid[r+1][c] != 0:
                    v_adj += 1

    # Decide transformation based on adjacency counts
    if v_adj >= h_adj:
        # Apply vertical gravity
        new_grid = [[0 for _ in range(cols)] for _ in range(rows)]
        for c in range(cols):
            non_zeros = []
            for r in range(rows):
                if grid[r][c] != 0:
                    non_zeros.append(grid[r][c])

            # Place non-zero elements at the bottom of the column
            for i, val in enumerate(non_zeros):
                new_grid[rows - len(non_zeros) + i][c] = val
    else:
        # Apply horizontal gravity (to the right)
        new_grid = [[0 for _ in range(cols)] for _ in range(rows)]
        for r in range(rows):
            non_zeros = []
            for c in range(cols):
                if grid[r][c] != 0:
                    non_zeros.append(grid[r][c])

            # Place non-zero elements at the right of the row
            for i, val in enumerate(non_zeros):
                new_grid[r][cols - len(non_zeros) + i] = val

    return new_grid

def grid_to_string(grid):
    return "\n".join(" ".join(map(str, row)) for row in grid)

# Test Input
