import json

def solve(grid):
    # Find unique non-zero colors and their topmost row index
    colors_top_row = {}
    for r, row in enumerate(grid):
        for c, val in enumerate(row):
            if val != 0:
                if val not in colors_top_row:
                    colors_top_row[val] = r

    # Create a copy of the grid to modify
    output_grid = [list(row) for row in grid]

    # Apply the transformation
    for color, top_row_idx in colors_top_row.items():
        for c, val in enumerate(output_grid[top_row_idx]):
